import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;

import java.net.URI;
import java.net.URISyntaxException;
import java.util.logging.Level;
import java.util.logging.Logger;

@Service
public class WebhookHandler {

    private static final Logger logger = Logger.getLogger(WebhookHandler.class.getName());

    @Autowired
    private RestTemplate restTemplate;

    public String processWebhook(String url) {
        try {
            URI uri = new URI(url);
            HttpHeaders headers = new HttpHeaders();
            headers.setContentType(MediaType.APPLICATION_JSON);

            HttpEntity<String> request = new HttpEntity<>(headers, null);

            String response = restTemplate.exchange(uri, HttpMethod.GET, request, String.class).getBody();

            return response;
        } catch (URISyntaxException e) {
            logger.log(Level.SEVERE, "Invalid URL", e);
            throw new RuntimeException("Invalid URL: " + url, e);
        }
    }

    public void processWebhookWithHeaders(String url, HttpHeaders headers) {
        try {
            URI uri = new URI(url);

            HttpEntity<String> request = new HttpEntity<>(headers, null);

            String response = restTemplate.exchange(uri, HttpMethod.GET, request, String.class).getBody();

            return response;
        } catch (URISyntaxException e) {
            logger.log(Level.SEVERE, "Invalid URL", e);
            throw new RuntimeException("Invalid URL: " + url, e);
        }
    }
}